const report = $input.first().json;
const checks = report.checks || {};
const summary = report.summary || {};
const ts = new Date(report.timestamp).toLocaleString('en-US', { timeZone: 'Asia/Manila', dateStyle: 'full', timeStyle: 'short' });

const icon = (s) => s === 'pass' ? '✅' : s === 'warn' ? '⚠️' : '❌';
const color = (s) => s === 'pass' ? '#16a34a' : s === 'warn' ? '#d97706' : '#dc2626';
const bg = (s) => s === 'pass' ? '#f0fdf4' : s === 'warn' ? '#fffbeb' : '#fef2f2';

const overallStatus = summary.failures > 0 ? 'CRITICAL' : summary.warnings > 0 ? 'WARNINGS' : 'ALL CLEAR';
const overallColor = summary.failures > 0 ? '#dc2626' : summary.warnings > 0 ? '#d97706' : '#16a34a';

let rows = '';
for (const [name, check] of Object.entries(checks)) {
  const c = check;
  const label = name.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
  let detail = c.message;
  if (c.details && typeof c.details === 'object') {
    const entries = Object.entries(c.details).filter(([k,v]) => typeof v !== 'object').map(([k,v]) => `${k}: ${v}`).join(' | ');
    if (entries) detail += `<br/><span style="font-size:11px;color:#6b7280;">${entries}</span>`;
  }
  rows += `<tr><td style="padding:10px 14px;border-bottom:1px solid #f3f4f6;">${icon(c.status)}</td><td style="padding:10px 14px;border-bottom:1px solid #f3f4f6;font-weight:600;color:#374151;">${label}</td><td style="padding:10px 14px;border-bottom:1px solid #f3f4f6;color:${color(c.status)};">${detail}</td></tr>`;
}

const html = `
<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;max-width:700px;margin:0 auto;">
  <div style="background:${overallColor};color:white;padding:20px 24px;border-radius:12px 12px 0 0;">
    <h1 style="margin:0;font-size:20px;">🏥 The Reach Daily Health Report — ${overallStatus}</h1>
    <p style="margin:6px 0 0;font-size:13px;opacity:0.9;">${ts}</p>
  </div>
  <div style="background:white;padding:16px 24px;border:1px solid #e5e7eb;">
    <div style="display:flex;gap:16px;margin-bottom:16px;">
      <div style="text-align:center;padding:10px 16px;background:#f0fdf4;border-radius:8px;flex:1;"><span style="font-size:22px;font-weight:800;color:#16a34a;">${summary.passed}</span><br/><span style="font-size:11px;color:#6b7280;">Passed</span></div>
      <div style="text-align:center;padding:10px 16px;background:#fffbeb;border-radius:8px;flex:1;"><span style="font-size:22px;font-weight:800;color:#d97706;">${summary.warnings}</span><br/><span style="font-size:11px;color:#6b7280;">Warnings</span></div>
      <div style="text-align:center;padding:10px 16px;background:#fef2f2;border-radius:8px;flex:1;"><span style="font-size:22px;font-weight:800;color:#dc2626;">${summary.failures}</span><br/><span style="font-size:11px;color:#6b7280;">Failures</span></div>
    </div>
  </div>
  <table style="width:100%;border-collapse:collapse;background:white;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 12px 12px;overflow:hidden;">
    <thead><tr style="background:#f9fafb;"><th style="padding:8px 14px;text-align:left;font-size:11px;color:#6b7280;text-transform:uppercase;"></th><th style="padding:8px 14px;text-align:left;font-size:11px;color:#6b7280;text-transform:uppercase;">Check</th><th style="padding:8px 14px;text-align:left;font-size:11px;color:#6b7280;text-transform:uppercase;">Result</th></tr></thead>
    <tbody>${rows}</tbody>
  </table>
  <p style="text-align:center;font-size:11px;color:#9ca3af;margin-top:16px;">The Reach Health Monitor</p>
</div>`;

return [{ json: { subject: `${icon(summary.failures > 0 ? 'fail' : summary.warnings > 0 ? 'warn' : 'pass')} The Reach Health: ${overallStatus} — ${summary.passed}/${summary.total} passed`, html, summary: report.summary } }];
